const body = $json.body;
const data = body.data;
const key = data.key;
const message = data.message;

// Extraer texto del mensaje
const messageText = message.conversation || 
                   message.extendedTextMessage?.text || 
                   message.imageMessage?.caption || '';

// Si no hay texto, skip
if (!messageText || messageText.trim() === '') {
  return [{ json: { skip: true, reason: 'Mensaje vacío' } }];
}

// Ignorar mensajes propios (fromMe)
if (key.fromMe === true) {
  return [{ json: { skip: true, reason: 'Mensaje propio' } }];
}

// Datos básicos
const remoteJid = key.remoteJid || '';
const isGroup = remoteJid.includes('@g.us');
const participantPn = key.participantPn || '';
const senderName = data.pushName || 'Usuario';

// Convertir timestamp a America/New_York
const timestamp = new Date(data.messageTimestamp * 1000);
const nyTime = new Date(timestamp.toLocaleString('en-US', { timeZone: 'America/New_York' }));

const year = nyTime.getFullYear();
const month = String(nyTime.getMonth() + 1).padStart(2, '0');
const day = String(nyTime.getDate()).padStart(2, '0');
const hours = String(nyTime.getHours()).padStart(2, '0');
const minutes = String(nyTime.getMinutes()).padStart(2, '0');
const seconds = String(nyTime.getSeconds()).padStart(2, '0');

const fecha = `${year}-${month}-${day}`;
const hora = `${hours}:${minutes}:${seconds}`;

// Detectar si menciona a Robotina
const mencionaRobotina = /robotina|@robotina/i.test(messageText);

// Detectar tipo de mensaje
const patronAsignacion = /^(Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday)\s+\d{1,2}\/\d{1,2}\/\d{4}/i;
const esAsignacion = patronAsignacion.test(messageText.trim());

let fechaServicio = null;
if (esAsignacion) {
  const fechaMatch = messageText.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
  if (fechaMatch) {
    const parte1 = fechaMatch[1].padStart(2, '0');
    const parte2 = fechaMatch[2].padStart(2, '0');
    const anio = fechaMatch[3];

    let dia, mes;
    if (parseInt(parte1) > 12) {
      dia = parte1;
      mes = parte2;
    } else if (parseInt(parte2) > 12) {
      mes = parte1;
      dia = parte2;
    } else {
      mes = parte1;
      dia = parte2;
    }

    fechaServicio = `${anio}-${mes}-${dia}`;
  }
}

let tipoMensaje = 'general';
if (esAsignacion) {
  tipoMensaje = 'asignacion';
}

return [{
  json: {
    fecha_envio: fecha,
    hora_envio: hora,
    mensaje_texto: messageText,
    sender_name: senderName,
    sender_number: participantPn.replace('@s.whatsapp.net', ''),
    remote_jid: remoteJid,
    message_id: key.id,
    tipo_mensaje: tipoMensaje,
    fecha_servicio: fechaServicio,
    isGroup: isGroup,
    mencionaRobotina: mencionaRobotina,
    skip: false
  }
}];

const output = $input.first().json.output;
const remoteJid = $('Extraer Datos Mensaje').first().json.remote_jid;

return [{
  json: {
    number: remoteJid,
    text: output
  }
}];
